-/// Returns true if the command is a control operation that must run outside a
-/// transaction (Shutdown, Vacuum, Checkpoint).
-fn is_control_command(cmd: &WriteCommand) -> bool {
-    matches!(
-        cmd,
-        WriteCommand::Shutdown { .. }
-            | WriteCommand::Vacuum { .. }
-            | WriteCommand::Checkpoint { .. }
-    )
